$blogDir = 'c:\Users\HOLA\OneDrive\Escritorio\juristam-web\blog'
$utf8noBOM = New-Object System.Text.UTF8Encoding $false
$updated = 0; $skipped = 0; $notFound = 0

function Update-Meta {
    param($f, $t, $d)
    $path = Join-Path $blogDir $f
    if (-not (Test-Path $path)) { Write-Host "NOT FOUND: $f"; $script:notFound++; return }
    $c = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)
    $orig = $c
    $m = [regex]::Match($c, '<title>[^<]*</title>')
    if ($m.Success) { $c = $c.Replace($m.Value, '<title>' + $t + '</title>') }
    $m = [regex]::Match($c, '<meta\s+name="description"\s+content="[^"]*"[^>]*/?>'); if (-not $m.Success) { $m = [regex]::Match($c, '<meta\s+content="[^"]*"\s+name="description"[^>]*/?>') }
    if ($m.Success) { $ov = [regex]::Match($m.Value, '(?<=content=")[^"]*').Value; $c = $c.Replace($m.Value, $m.Value.Replace('content="' + $ov + '"', 'content="' + $d + '"')) }
    $m = [regex]::Match($c, '<meta\s+property="og:title"\s+content="[^"]*"[^>]*/?>'); if (-not $m.Success) { $m = [regex]::Match($c, '<meta\s+content="[^"]*"\s+property="og:title"[^>]*/?>') }
    if ($m.Success) { $ov = [regex]::Match($m.Value, '(?<=content=")[^"]*').Value; $c = $c.Replace($m.Value, $m.Value.Replace('content="' + $ov + '"', 'content="' + $t + '"')) }
    $m = [regex]::Match($c, '<meta\s+property="og:description"\s+content="[^"]*"[^>]*/?>'); if (-not $m.Success) { $m = [regex]::Match($c, '<meta\s+content="[^"]*"\s+property="og:description"[^>]*/?>') }
    if ($m.Success) { $ov = [regex]::Match($m.Value, '(?<=content=")[^"]*').Value; $c = $c.Replace($m.Value, $m.Value.Replace('content="' + $ov + '"', 'content="' + $d + '"')) }
    if ($c -ne $orig) { [System.IO.File]::WriteAllText($path, $c, $utf8noBOM); Write-Host "OK: $f"; $script:updated++ } else { $script:skipped++ }
}

